   277	fn should_add_parens(body: &AstNode<'_, FunctionBody<'_>>) -> bool {
   278	    let AstNodes::ExpressionStatement(stmt) = body.statements().first().unwrap().as_ast_nodes()
   279	    else {
   280	        unreachable!()
   281	    };
   282	
   283	    // Add parentheses to avoid confusion between `a => b ? c : d` and `a <= b ? c : d`
   284	    // but only if the body isn't an object/function or class expression because parentheses are always required in that
   285	    // case and added by the object expression itself
   286	    if matches!(&stmt.expression, Expression::ConditionalExpression(_)) {
   287	        !matches!(
   288	            ExpressionLeftSide::leftmost(stmt.expression()).as_ref(),
   289	            Expression::ObjectExpression(_)
   290	                | Expression::FunctionExpression(_)
   291	                | Expression::ClassExpression(_)
   292	        )
   293	    } else {
   294	        false
   295	    }
   296	}
