   303	/// Writes the arrow function type parameters, parameters, and return type annotation.
   304	///
   305	/// Formats the parameters and return type annotation without any soft line breaks if `is_grouped_call_argument` is `true`
   306	/// so that the parameters and return type are kept on the same line.
   307	fn format_signature<'a, 'b>(
   308	    arrow: &'b AstNode<'a, ArrowFunctionExpression<'a>>,
   309	    is_grouped_call_argument: bool,
   310	    is_first_in_chain: bool,
   311	    cache_mode: FunctionCacheMode,
   312	) -> impl Format<'a> + 'b {
   313	    format_with(move |f| {
   314	        let content = format_with(|f| {
   315	            group(&format_args!(
   316	                arrow.r#async().then_some("async "),
   317	                arrow.type_parameters(),
   318	                arrow.params(),
   319	                arrow.return_type().map(FormatNodeWithoutTrailingComments),
   320	            ))
   321	            .fmt(f);
   322	        });
   323	        let format_head = FormatContentWithCacheMode::new(arrow.params.span, content, cache_mode);
   324	
   325	        if is_grouped_call_argument {
   326	            // The first arrow's soft lines have already been removed in the CallArguments.
   327	            if is_first_in_chain {
   328	                write!(f, format_head);
   329	            } else {
   330	                write!(f, [space()]);
   331	                let mut buffer = RemoveSoftLinesBuffer::new(f);
   332	                write!(buffer, format_head);
   333	            }
   334	        } else {
   335	            write!(
   336	                f,
   337	                [
   338	                    // This soft break is placed outside of the group to ensure
   339	                    // that the parameter group only tries to write on a single
   340	                    // line and can't break pre-emptively without also causing
   341	                    // the parent (i.e., this ArrowChain) to break first.
   342	                    (!is_first_in_chain).then_some(soft_line_break_or_space()),
   343	                    format_head
   344	                ]
   345	            );
   346	        }
   347	
   348	        // Print comments before the fat arrow (`=>`)
   349	        let comments_before_fat_arrow =
   350	            f.context().comments().comments_before_character(arrow.params.span().end, b'=');
   351	        let content = FormatTrailingComments::Comments(comments_before_fat_arrow);
   352	        write!(f, [FormatContentWithCacheMode::new(arrow.span, content, cache_mode)]);
   353	    })
   354	}
