   356	/// Formats a function body with additional caching depending on [`mode`](Self::mode).
   357	pub struct FormatMaybeCachedFunctionBody<'a, 'b> {
   358	    /// The body to format.
   359	    pub body: &'b AstNode<'a, FunctionBody<'a>>,
   360	
   361	    /// Is the function body an arrow expression? i.e. `() => expr` instead of `() => {}`
   362	    pub expression: bool,
   363	
   364	    /// If the body should be cached or if the formatter should try to retrieve it from the cache.
   365	    pub mode: FunctionCacheMode,
   366	}
   367	
   368	impl<'a> Format<'a> for FormatMaybeCachedFunctionBody<'a, '_> {
   369	    fn fmt(&self, f: &mut Formatter<'_, 'a>) {
   370	        let content = format_with(|f| {
   371	            if self.expression
   372	                && let AstNodes::ExpressionStatement(s) =
   373	                    &self.body.statements().first().unwrap().as_ast_nodes()
   374	            {
   375	                return s.expression().fmt(f);
   376	            }
   377	            self.body.fmt(f);
   378	        });
   379	        FormatContentWithCacheMode::new(self.body.span, content, self.mode).fmt(f);
   380	    }
   381	}
   382	
   383	/// Format a sequence expression in an arrow function body that has a leading comment.
   384	///
   385	/// When an arrow function body is a sequence expression (e.g., `() => (a, b, c)`) and has
   386	/// a leading comment, special formatting is needed to place the comment correctly:
   387	///
   388	/// ```js
   389	/// const f = () =>
   390	///   // comment
   391	///   (a, b, c);
   392	/// ```
   393	///
   394	/// Returns `Some(formatter)` if the sequence has a leading comment, `None` otherwise.
   395	/// When `None`, the caller should use normal formatting with `soft_block_indent`.
   396	///
   397	/// Handles `oxfmt-ignore` by preserving original source text when suppressed.
   398	fn format_sequence_with_leading_comment<'a, 'b>(
   399	    sequence_span: Span,
   400	    format_body: &'b impl Format<'a>,
   401	    f: &Formatter<'_, 'a>,
   402	) -> Option<impl Format<'a> + 'b> {
   403	    if !f.comments().has_comment_before(sequence_span.start) {
   404	        return None;
   405	    }
   406	
   407	    let is_suppressed = f.comments().is_suppressed(sequence_span.start);
   408	
   409	    let format_sequence = format_with(move |f| {
   410	        write!(f, [format_leading_comments(sequence_span), "("]);
   411	        if is_suppressed {
   412	            write!(f, FormatSuppressedNode(sequence_span));
   413	        } else {
   414	            write!(f, format_body);
   415	        }
   416	        write!(f, [")"]);
   417	    });
   418	
   419	    Some(format_with(move |f| {
   420	        write!(f, group(&indent(&format_args!(hard_line_break(), format_sequence))));
   421	    }))
   422	}
